import{_ as a,o as e,c as n,a2 as i}from"./chunks/framework.LN3EJxkW.js";const b=JSON.parse('{"title":"我把一份工程师 Roadmap 做成了网站：从 Markdown 仓库到 GitHub Pages 的完整复盘","description":"","frontmatter":{},"headers":[],"relativePath":"projects/lili-roadmap-site-retrospective.md","filePath":"projects/lili-roadmap-site-retrospective.md","lastUpdated":null}'),l={name:"projects/lili-roadmap-site-retrospective.md"};function p(t,s,r,d,o,c){return e(),n("div",null,[...s[0]||(s[0]=[i(`<h1 id="我把一份工程师-roadmap-做成了网站-从-markdown-仓库到-github-pages-的完整复盘" tabindex="-1">我把一份工程师 Roadmap 做成了网站：从 Markdown 仓库到 GitHub Pages 的完整复盘 <a class="header-anchor" href="#我把一份工程师-roadmap-做成了网站-从-markdown-仓库到-github-pages-的完整复盘" aria-label="Permalink to &quot;我把一份工程师 Roadmap 做成了网站：从 Markdown 仓库到 GitHub Pages 的完整复盘&quot;">​</a></h1><p>一开始，我只是想把一份很长的 Software Engineer Roadmap 整理清楚。</p><p>真正做下去后才发现，难的不是“把 Markdown 放上网”，而是同时守住三件事：内容能长期扩展，目录能让人按难度阅读，发布后旧链接还不能突然失效。</p><p>这个项目最后从一份大型 Roadmap，逐步变成了五条可以独立学习的成长路线，并建立了 VitePress 网站、GitHub Pages 发布链路、旧路径重定向和版本发布记录。</p><p>中间也并不顺利：Pages 出现过 404，最初的自动部署工作流连续启动失败；目录重命名以后，已经发出去的链接又面临失效。</p><p>这篇文章只记录这次项目中真实发生过的选择、问题和解决方法。</p><h2 id="最初的问题-一份大纲很完整-但不适合长期维护" tabindex="-1">最初的问题：一份大纲很完整，但不适合长期维护 <a class="header-anchor" href="#最初的问题-一份大纲很完整-但不适合长期维护" aria-label="Permalink to &quot;最初的问题：一份大纲很完整，但不适合长期维护&quot;">​</a></h2><p>原始材料是一份覆盖面很大的 Software Engineer Roadmap Markdown。它能表达“要学什么”，但内容继续增加以后，会遇到几个很实际的问题：</p><ul><li>一个文件承载太多层级，阅读和编辑都越来越重。</li><li>前端、产品、交互、AI、后端与数据混在一起，不容易看出每条路线的起点和进阶顺序。</li><li>大纲可以列知识点，却不适合承载每个知识点的解释、案例、练习和来源。</li><li>如果只为某个编辑器设计链接，换到 GitHub 或 VS Code 后可能无法正常导航。</li></ul><p>所以第一步不是选网站框架，而是先重新定义内容结构。</p><p>当前仓库把能力拆成五个方向：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01-frontend/</span></span>
<span class="line"><span>02-product/</span></span>
<span class="line"><span>03-interaction-design/</span></span>
<span class="line"><span>04-ai/</span></span>
<span class="line"><span>05-backend-data/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>每个方向再维护自己的入口、路线图、笔记、日常练习和项目：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01-frontend/</span></span>
<span class="line"><span>├── README.md</span></span>
<span class="line"><span>├── roadmap.md</span></span>
<span class="line"><span>├── notes/</span></span>
<span class="line"><span>├── daily/</span></span>
<span class="line"><span>└── projects.md</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>这次拆分有一个很重要的原则：五条路线可以组合，但也必须能独立开始。</p><p>比如只想学产品的人，不需要先读完前端；刚接触 Web 的人，也能从前端路线的基础阶段开始。仓库根目录负责总览，各方向的 <code>README.md</code> 负责解释本路线怎么走，<code>roadmap.md</code> 负责学习顺序，<code>notes/</code> 承载具体知识点。</p><h2 id="为什么继续使用-markdown-而不是直接把内容写进网站" tabindex="-1">为什么继续使用 Markdown，而不是直接把内容写进网站 <a class="header-anchor" href="#为什么继续使用-markdown-而不是直接把内容写进网站" aria-label="Permalink to &quot;为什么继续使用 Markdown，而不是直接把内容写进网站&quot;">​</a></h2><p>这个项目一直保留 Markdown 作为内容源，不把知识库锁进某个网站后台。</p><p>原因很直接：同一份内容需要在三个环境里使用。</p><table tabindex="0"><thead><tr><th>使用场景</th><th>需要解决的问题</th></tr></thead><tbody><tr><td>Obsidian</td><td>本地阅读、整理与长期积累</td></tr><tr><td>VS Code</td><td>批量编辑、搜索、脚本校验与 Git 操作</td></tr><tr><td>GitHub</td><td>版本历史、公开协作与直接阅读</td></tr></tbody></table><p>因此，仓库内部链接统一使用普通相对 Markdown 链接，例如：</p><div class="language-markdown vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#032F62;--shiki-light-text-decoration:underline;--shiki-dark:#DBEDFF;--shiki-dark-text-decoration:underline;">前端路线图</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">](</span><span style="--shiki-light:#24292E;--shiki-light-text-decoration:underline;--shiki-dark:#E1E4E8;--shiki-dark-text-decoration:underline;">../01-frontend/roadmap.md</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>没有把 Obsidian 专用的 Wiki Link 当作唯一导航方式，也没有为了网站改成只能由 VitePress 识别的内容格式。</p><p>这个选择后来很省事：建立网站时，VitePress 直接读取现有 Markdown；即使网站暂时不可用，仓库里的内容仍然可以阅读和维护。</p><h2 id="从内容仓库到网站-我补了哪一层" tabindex="-1">从内容仓库到网站，我补了哪一层 <a class="header-anchor" href="#从内容仓库到网站-我补了哪一层" aria-label="Permalink to &quot;从内容仓库到网站，我补了哪一层&quot;">​</a></h2><p>仓库内容稳定后，才加入 VitePress。它在这里承担的是“展示层”，不是新的内容源。</p><p>整体链路如下：</p><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;main：Markdown 与配置&quot;] --&gt; B[&quot;pnpm docs:build&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[&quot;.vitepress/dist：静态产物&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[&quot;gh-pages 分支根目录&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[&quot;GitHub Pages&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[&quot;Release 与 Deployments 入口&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p><code>main</code> 始终保留源码，<code>gh-pages</code> 只保存构建后的静态文件。这样可以避免把大量生成文件混进内容提交，也能明确区分“正在编辑的内容”和“已经上线的版本”。</p><p>项目增加的核心结构并不多：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.</span></span>
<span class="line"><span>├── .vitepress/</span></span>
<span class="line"><span>│   ├── config.mts</span></span>
<span class="line"><span>│   └── theme/</span></span>
<span class="line"><span>├── public/</span></span>
<span class="line"><span>│   └── favicon.svg</span></span>
<span class="line"><span>├── index.md</span></span>
<span class="line"><span>├── package.json</span></span>
<span class="line"><span>└── pnpm-lock.yaml</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>本地开发和构建命令也保持得很短：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs:dev</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs:build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs:preview</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>这里的顺序不能只停在 <code>docs:dev</code>。开发服务器能打开，不代表生产产物一定正确；部署前至少要执行一次 <code>docs:build</code>，需要检查最终路由时再运行 <code>docs:preview</code>。</p><h2 id="关键选择一-项目站点必须配置正确的-base" tabindex="-1">关键选择一：项目站点必须配置正确的 <code>base</code> <a class="header-anchor" href="#关键选择一-项目站点必须配置正确的-base" aria-label="Permalink to &quot;关键选择一：项目站点必须配置正确的 \`base\`&quot;">​</a></h2><p>这个站点不是发布在域名根路径，而是 GitHub Pages 的仓库子路径：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://justcdq.github.io/Lili/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>所以 VitePress 配置里明确写了：</p><div class="language-ts vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> default</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> defineConfig</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  base: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;/Lili/&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  cleanUrls: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">})</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><code>base</code> 决定构建后的资源与站内链接以哪个公共路径为起点。如果网站实际位于 <code>/Lili/</code>，配置却仍按 <code>/</code> 生成资源地址，页面即使返回 HTML，脚本、样式或导航也可能请求到错误位置。</p><p>这类问题在本地根路径预览时不一定明显，所以验证不能只看首页“有没有白屏”，还要检查浏览器网络请求和一个真实的深层页面。</p><h2 id="关键选择二-侧边栏从目录生成-而不是手写几百条链接" tabindex="-1">关键选择二：侧边栏从目录生成，而不是手写几百条链接 <a class="header-anchor" href="#关键选择二-侧边栏从目录生成-而不是手写几百条链接" aria-label="Permalink to &quot;关键选择二：侧边栏从目录生成，而不是手写几百条链接&quot;">​</a></h2><p>随着笔记数量增加，手工维护侧边栏很快会变成重复劳动，也容易出现文章已经存在、导航却漏掉的情况。</p><p>当前配置会递归读取各方向的 <code>notes/</code> 与 <code>daily/</code>，从每篇 Markdown 的一级标题生成导航文字，再根据文件路径生成链接。</p><p>这带来两个直接收益：</p><ol><li>新增文章后，不需要再把同一条链接复制到一份巨大的站点配置里。</li><li>文件系统里的学习顺序，可以直接反映到侧边栏顺序中。</li></ol><p>但第二点也暴露了新的问题：如果目录名只有 <code>html</code>、<code>css</code>、<code>javascript</code>，按字母排序并不等于按学习难度排序。</p><h2 id="关键选择三-用数字前缀表达路线顺序" tabindex="-1">关键选择三：用数字前缀表达路线顺序 <a class="header-anchor" href="#关键选择三-用数字前缀表达路线顺序" aria-label="Permalink to &quot;关键选择三：用数字前缀表达路线顺序&quot;">​</a></h2><p>为了让目录顺序与 Roadmap 的推进顺序一致，笔记目录后来统一增加了数字前缀。</p><p>前端方向从：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>web-basics/</span></span>
<span class="line"><span>html/</span></span>
<span class="line"><span>css/</span></span>
<span class="line"><span>javascript/</span></span>
<span class="line"><span>typescript-frameworks/</span></span>
<span class="line"><span>browser-runtime/</span></span>
<span class="line"><span>application-architecture/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>改成：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>00-web-basics/</span></span>
<span class="line"><span>01-html/</span></span>
<span class="line"><span>02-css/</span></span>
<span class="line"><span>03-javascript/</span></span>
<span class="line"><span>04-typescript-frameworks/</span></span>
<span class="line"><span>05-browser-runtime/</span></span>
<span class="line"><span>06-application-architecture/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>其他方向也采用相同方式。交互设计中的模式目录还有第二层编号，例如导航、输入、数据、反馈、操作与协作也按路线顺序排列。</p><p>这里没有把顺序只写在网站配置中。目录本身就表达顺序，因此在 Obsidian、VS Code 文件树和 GitHub 页面里也能得到一致结果。</p><h2 id="第一个坑-github-pages-不是-加完配置就会自动上线" tabindex="-1">第一个坑：GitHub Pages 不是“加完配置就会自动上线” <a class="header-anchor" href="#第一个坑-github-pages-不是-加完配置就会自动上线" aria-label="Permalink to &quot;第一个坑：GitHub Pages 不是“加完配置就会自动上线”&quot;">​</a></h2><p>项目最初加入过一份 GitHub Actions 工作流，计划在 <code>main</code> 推送后完成安装、构建、上传产物和 Pages 部署。</p><p>但真实结果是：与这份工作流相关的三次运行都停在 <code>startup_failure</code>，预期站点出现了 404。仅凭仓库历史不能把失败归因到某一行 YAML，因此这次复盘不把猜测写成根因。</p><p>当时真正有效的处理方式，是缩短发布链路：</p><ol><li>在本地执行 <code>pnpm docs:build</code>。</li><li>确认 <code>.vitepress/dist</code> 已生成完整静态站点。</li><li>使用独立的 <code>gh-pages</code> 分支保存构建产物。</li><li>将 GitHub Pages 的发布源指向该分支根目录。</li><li>等待 Pages 构建完成，再访问公开 URL 验证。</li></ol><p>切换以后，<code>main</code> 上的自定义 Pages 工作流被删除，README 也改为说明当前实际发布方式。切换初期，<code>gh-pages</code> 分支触发的 Pages 构建也出现过一次 <code>startup_failure</code>；完成发布源配置后，远端随后五次可见的 Pages 构建记录均显示成功。</p><p>这次故障让我更确定一件事：处理 404 时，不要同时改构建配置、路由、域名和发布源。先回答四个问题：</p><ul><li>本地生产构建是否成功？</li><li>构建产物的根目录里是否有入口文件？</li><li>Pages 当前读取的是哪个分支、哪个目录？</li><li>公开 URL 是否包含仓库子路径？</li></ul><p>只有前一层被验证后，再检查下一层，定位会快很多。</p><h2 id="第二个坑-目录改得更清楚-旧链接却全部变旧了" tabindex="-1">第二个坑：目录改得更清楚，旧链接却全部变旧了 <a class="header-anchor" href="#第二个坑-目录改得更清楚-旧链接却全部变旧了" aria-label="Permalink to &quot;第二个坑：目录改得更清楚，旧链接却全部变旧了&quot;">​</a></h2><p>给目录增加数字前缀后，新的站点结构更容易读，但旧地址不会自动跟着移动。</p><p>例如旧页面可能是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/01-frontend/notes/web-basics/01-files-paths-encoding-archives.html</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>新页面变成：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/01-frontend/notes/00-web-basics/01-files-paths-encoding-archives.html</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果只完成 Git 文件重命名，之前发到聊天、收藏夹、Release 或搜索结果里的旧链接都会返回 404。</p><p>项目采用的解决方式是在 <code>.vitepress/config.mts</code> 中维护旧目录到新目录的映射：</p><div class="language-ts vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> noteDirectoryRedirects</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &#39;01-frontend/notes/web-basics&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &#39;01-frontend/notes/00-web-basics&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &#39;01-frontend/notes/html&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &#39;01-frontend/notes/01-html&#39;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>构建结束时，程序遍历新目录里的 Markdown 文件，在旧目录对应位置生成同名 HTML。跳转页同时包含：</p><ul><li><code>meta refresh</code>，让不执行 JavaScript 的页面也能跳转；</li><li><code>canonical</code>，声明应该使用的新地址；</li><li><code>location.replace(...)</code>，避免旧页面在浏览历史中反复出现。</li></ul><p>这里还有一个容易遗漏的细节：重定向目标是根据构建产物之间的相对路径计算的，不是把某个域名硬编码进每个文件。这样站点公共路径变化时，跳转逻辑不必逐页重写。</p><h2 id="第三个坑-源码链接正常-不代表构建产物里一定存在目标" tabindex="-1">第三个坑：源码链接正常，不代表构建产物里一定存在目标 <a class="header-anchor" href="#第三个坑-源码链接正常-不代表构建产物里一定存在目标" aria-label="Permalink to &quot;第三个坑：源码链接正常，不代表构建产物里一定存在目标&quot;">​</a></h2><p>仓库中有一些笔记会链接到可运行示例，而 VitePress 默认主要处理 Markdown 与主题资源。为了让示例在网站中也可访问，构建插件会把五个方向下存在的 <code>examples/</code> 递归复制到 <code>.vitepress/dist</code> 的对应位置。</p><p>也就是说，验证链接时要区分两件事：</p><ul><li>Markdown 源文件中的相对路径是否正确；</li><li>生产构建后，对应文件是否真的进入了静态站点。</li></ul><p>只检查编辑器里的跳转，无法覆盖第二个问题。</p><h2 id="发布不只是-页面能打开-还要让入口可被找到" tabindex="-1">发布不只是“页面能打开”，还要让入口可被找到 <a class="header-anchor" href="#发布不只是-页面能打开-还要让入口可被找到" aria-label="Permalink to &quot;发布不只是“页面能打开”，还要让入口可被找到&quot;">​</a></h2><p>站点上线后，我又补了几个公开入口。</p><p>首先，仓库 README 顶部直接提供在线阅读链接，并写清当前发布分支和本地构建命令。</p><p>其次，版本通过 GitHub Release 对外说明。当前两个 Release 的正文都包含“在线阅读”入口，其中 <code>v0.2.0</code> 还记录了 VitePress 构建与 GitHub Pages 发布成功。</p><p>最后，GitHub Pages 生成的 Deployment 成功状态也带有环境地址。这样从仓库的 Deployments 区域进入时，可以直接打开对应站点，而不是只能看到一条没有去向的成功记录。</p><p>Release 和 Deployment 的职责并不相同：</p><table tabindex="0"><thead><tr><th>入口</th><th>更适合表达什么</th></tr></thead><tbody><tr><td>README</td><td>项目的长期固定入口与使用方式</td></tr><tr><td>Release</td><td>某个内容版本新增了什么、验证了什么</td></tr><tr><td>Deployment</td><td>某次线上部署的状态与环境地址</td></tr></tbody></table><p>把站点地址放进这三个位置，不是重复粘贴，而是让读者从不同任务入口都能找到最终成果。</p><h2 id="最终成果" tabindex="-1">最终成果 <a class="header-anchor" href="#最终成果" aria-label="Permalink to &quot;最终成果&quot;">​</a></h2><p>这次改造完成后，项目形成了这样一套结构：</p><ul><li>五条可以独立开始、也能组合学习的长期路线；</li><li>以 Markdown 为唯一内容源，兼容 Obsidian、VS Code 与 GitHub；</li><li>VitePress 自动读取目录和一级标题生成网站导航；</li><li><code>main</code> 保存源码，<code>gh-pages</code> 保存静态构建产物；</li><li>仓库子路径通过 <code>base: &#39;/Lili/&#39;</code> 明确配置；</li><li>路线目录按难度加数字前缀；</li><li>旧目录下的文章地址保留逐页重定向；</li><li>示例文件会进入生产构建产物；</li><li>README、Release 和 Deployment 都能找到在线站点。</li></ul><p>公开站点地址是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://justcdq.github.io/Lili/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>对我来说，这次最有价值的结果不是“多了一个文档网站”，而是内容结构、阅读顺序、构建结果和发布记录终于由同一套仓库约束起来。</p><h2 id="一份可以复用的发布检查清单" tabindex="-1">一份可以复用的发布检查清单 <a class="header-anchor" href="#一份可以复用的发布检查清单" aria-label="Permalink to &quot;一份可以复用的发布检查清单&quot;">​</a></h2><p>如果你也想把一个 Markdown 知识库发布成站点，可以按下面的顺序检查。</p><h3 id="内容结构" tabindex="-1">内容结构 <a class="header-anchor" href="#内容结构" aria-label="Permalink to &quot;内容结构&quot;">​</a></h3><ul><li>[ ] 根目录能说明项目目标、读者和使用方式。</li><li>[ ] 大主题已拆成可以独立进入的方向。</li><li>[ ] 目录名本身能够表达稳定的学习顺序。</li><li>[ ] 仓库内部使用普通相对 Markdown 链接。</li><li>[ ] 内容源只有一份，网站不再复制一份正文。</li></ul><h3 id="本地构建" tabindex="-1">本地构建 <a class="header-anchor" href="#本地构建" aria-label="Permalink to &quot;本地构建&quot;">​</a></h3><ul><li>[ ] 锁文件已经提交，安装结果可复现。</li><li>[ ] <code>pnpm docs:build</code> 能完成生产构建。</li><li>[ ] <code>pnpm docs:preview</code> 下首页和深层页面都能打开。</li><li>[ ] 浏览器控制台没有影响使用的错误。</li><li>[ ] 示例、图片和其他静态文件进入了构建产物。</li></ul><h3 id="github-pages" tabindex="-1">GitHub Pages <a class="header-anchor" href="#github-pages" aria-label="Permalink to &quot;GitHub Pages&quot;">​</a></h3><ul><li>[ ] 仓库站点的 <code>base</code> 与真实子路径一致。</li><li>[ ] Pages 发布源与实际方案一致。</li><li>[ ] 源码分支与静态产物分支职责清楚。</li><li>[ ] 发布后验证首页、任意深层页和静态资源。</li><li>[ ] 404 排查记录了构建、产物、发布源和 URL 四层证据。</li></ul><h3 id="目录迁移" tabindex="-1">目录迁移 <a class="header-anchor" href="#目录迁移" aria-label="Permalink to &quot;目录迁移&quot;">​</a></h3><ul><li>[ ] 重命名前列出会变化的公开 URL。</li><li>[ ] 旧路径有明确的新路径映射。</li><li>[ ] 重定向文件确实出现在生产构建中。</li><li>[ ] 旧链接和新链接都经过实际访问验证。</li><li>[ ] 后续删除重定向前，先确认旧链接已没有使用价值。</li></ul><h3 id="对外发布" tabindex="-1">对外发布 <a class="header-anchor" href="#对外发布" aria-label="Permalink to &quot;对外发布&quot;">​</a></h3><ul><li>[ ] README 有稳定的在线入口。</li><li>[ ] Release 写清版本内容和验证结果。</li><li>[ ] Deployment 成功状态能跳转到环境地址。</li><li>[ ] 文档和日志中没有 Token、私钥或本机敏感路径。</li><li>[ ] 提交源码、推送分支、创建 Release 和检查线上站点分开验证。</li></ul><h2 id="写在最后" tabindex="-1">写在最后 <a class="header-anchor" href="#写在最后" aria-label="Permalink to &quot;写在最后&quot;">​</a></h2><p>这次经历让我重新理解了“把文档发布成网站”这件事。</p><p>页面生成只是中间一步。真正需要长期维护的是：内容如何分层、顺序如何表达、旧链接如何继续工作、构建产物从哪里来、线上状态在哪里被验证。</p><p>如果你也维护过个人知识库或文档站，最让你头疼的是目录越改越乱、GitHub Pages 404，还是旧链接迁移？欢迎分享你的处理方式。</p><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://github.com/justCDQ/Lili" target="_blank" rel="noreferrer">Lili 仓库 README 与公开源码</a>，访问日期：2026-07-22。</li><li><a href="https://github.com/justCDQ/Lili/releases" target="_blank" rel="noreferrer">Lili Releases</a>，访问日期：2026-07-22。</li><li><a href="https://github.com/justCDQ/Lili/deployments" target="_blank" rel="noreferrer">Lili Deployments</a>，访问日期：2026-07-22。</li><li><a href="https://vitepress.dev/guide/deploy" target="_blank" rel="noreferrer">VitePress：Deploy Your VitePress Site</a>，访问日期：2026-07-22。</li><li><a href="https://docs.github.com/en/pages/getting-started-with-github-pages/configuring-a-publishing-source-for-your-github-pages-site" target="_blank" rel="noreferrer">GitHub Docs：Configuring a publishing source for your GitHub Pages site</a>，访问日期：2026-07-22。</li></ul>`,113)])])}const u=a(l,[["render",p]]);export{b as __pageData,u as default};
